        val firstSuperTypeEntry =
            children()
                .firstOrNull {
                    it.elementType == SUPER_TYPE_CALL_ENTRY ||
                        it.elementType == SUPER_TYPE_ENTRY ||
                        it.elementType == DELEGATED_SUPER_TYPE_ENTRY
                }
