            fromAstNode = commaAfterFirstEntry,
            toAstNode = lastChildLeafOrSelf(),
            nodeIndent = baseIndent,
            childIndent = childIndent,
            firstChildIndent = childIndent,
            lastChildIndent = childIndent,
        )
    }

    private fun ASTNode.findCommaAfterEntry(): ASTNode? {
        var leaf = lastChildLeafOrSelf()
        while (true) {
            leaf = leaf.nextLeaf(includeEmpty = true) ?: return null
            when {
                leaf.elementType == COMMA -> return leaf
                leaf.textContains('\n') -> return null
            }
        }
    }

    private fun ASTNode.columnBeforeOnLine(): Int {
        var width = 0
        var leaf: ASTNode? = prevLeaf(includeEmpty = true)
        while (leaf != null) {
            val text = leaf.text
            val index = text.lastIndexOf('\n')
            if (index >= 0) {
                width += text.substring(index + 1).visualWidth()
                return width
            }
            width += text.visualWidth()
            leaf = leaf.prevLeaf(includeEmpty = true)
        }
        return width
    }

    private fun String.visualWidth(): Int = replace("\t", " ".repeat(indentConfig.tabWidth)).length

    private fun indentTextOfVisualWidth(width: Int): String =
        when (indentConfig.indentStyle) {
            SPACE -> " ".repeat(width)
            TAB -> "\t".repeat(width / indentConfig.tabWidth)
        }

