import org.junit.jupiter.api.Test

internal class IndentationRuleSuperTypeListKtlintOfficialTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Indentation of class body is not impacted by multiline super type list in class header`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                    // body
                }
            """.trimIndent()

        val formattedCode =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasLintViolations(
                LintViolation(7, 1, "Unexpected indentation (8) (should be 4)"),
                LintViolation(8, 1, "Unexpected indentation (4) (should be 0)"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Indentation of explicit constructor with multiline super type list aligns super type list and does not over indent class body`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                    // body
                }
            """.trimIndent()

        val formattedCode =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                    BarFoo1,
                    BarFoo2 {
                // body
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasLintViolations(
                LintViolation(6, 1, "Unexpected indentation (4) (should be 8)"),
                LintViolation(7, 1, "Unexpected indentation (4) (should be 8)"),
                LintViolation(8, 1, "Unexpected indentation (8) (should be 4)"),
                LintViolation(9, 1, "Unexpected indentation (4) (should be 0)"),
            ).isFormattedAs(formattedCode)
    }
}
